import React, { useState } from 'react';
import { Search, Scroll, Shield, ChevronLeft, MapPin, Coins, AlertTriangle } from 'lucide-react';

const ScrollSearch = () => {
  const [searchTerm, setSearchTerm] = useState("");

  // Comprehensive dummy data for search
  const allScrolls = [
    { id: 1, title: "Griffin Menace at White Orchard", location: "Temeria", reward: "500 Gold", difficulty: "Medium", type: "Monster Contract" },
    { id: 2, title: "Collect 500 Rupees for Shield Repair", location: "Hyrule", reward: "Hylian Shield", difficulty: "Easy", type: "Fetch Quest" },
    { id: 3, title: "Mako Reactor Maintenance", location: "Midgar", reward: "2000 Gil", difficulty: "Hard", type: "Industrial" },
    { id: 4, title: "Train Robbery Assistance", location: "New Hanover", reward: "150 Gold", difficulty: "Medium", type: "Outlaw" },
    { id: 5, title: "Goblin Den Clearing", location: "Borderlands", reward: "Small Pouch", difficulty: "Easy", type: "Monster Contract" },
    { id: 6, title: "The Ghost of the Lighthouse", location: "Skellige", reward: "1200 Gold", difficulty: "Hard", type: "Investigation" },
    { id: 7, title: "Lost Cucco Retrieval", location: "Kakariko Village", reward: "Purple Rupee", difficulty: "Easy", type: "Fetch Quest" },
  ];

  const filteredScrolls = allScrolls.filter(scroll =>
    scroll.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
    scroll.location.toLowerCase().includes(searchTerm.toLowerCase()) ||
    scroll.type.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="min-h-screen bg-[#3d2b1f]/60 font-serif text-[#4a3728] backdrop-blur-[2px] p-6 lg:p-10">
      
      {/* NAVIGATION */}
      <button className="mb-8 flex items-center gap-2 text-[#d7ccc8] hover:text-white transition-colors uppercase text-sm font-bold tracking-widest group">
        <ChevronLeft size={20} className="group-hover:-translate-x-1 transition-transform" />
        Return to Guild Hall
      </button>

      <div className="max-w-5xl mx-auto space-y-10">
        
        {/* BIG SEARCH HEADER */}
        <section className="text-center space-y-6">
          <div className="inline-block relative">
            <h1 className="text-6xl font-black text-[#f5f5dc] uppercase tracking-tighter drop-shadow-2xl">
              The Great Archive
            </h1>
            <div className="h-1 w-full bg-gradient-to-r from-transparent via-[#b8860b] to-transparent mt-2" />
          </div>

          <div className="max-w-2xl mx-auto relative group">
            <div className="absolute -inset-1 bg-[#b8860b]/20 blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
            <div className="relative flex items-center bg-[#fdf6e3] border-4 border-[#3e2723] shadow-2xl p-2">
              <Search className="ml-4 text-[#8d6e63]" size={28} />
              <input 
                type="text"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Search by location, threat, or reward..."
                className="w-full bg-transparent px-6 py-4 text-2xl focus:outline-none italic placeholder-[#8d6e63]/40 font-bold"
              />
              {searchTerm && (
                <button 
                  onClick={() => setSearchTerm("")}
                  className="mr-4 text-xs font-black uppercase text-[#8d6e63] hover:text-[#8b0000]"
                >
                  Clear
                </button>
              )}
            </div>
          </div>
        </section>

        {/* SEARCH RESULTS AREA */}
        <main 
          className="min-h-[400px] shadow-inner relative overflow-hidden p-8 lg:p-12"
          style={{ 
            backgroundImage: 'url("https://www.transparenttextures.com/patterns/paper-fibers.png")',
            backgroundColor: 'rgba(253, 246, 227, 0.9)',
            backdropFilter: 'blur(8px)'
          }}
        >
          {/* Decorative Corner Pins */}
          <div className="absolute top-4 left-4 w-3 h-3 bg-[#3e2723] rounded-full opacity-30" />
          <div className="absolute top-4 right-4 w-3 h-3 bg-[#3e2723] rounded-full opacity-30" />
          <div className="absolute bottom-4 left-4 w-3 h-3 bg-[#3e2723] rounded-full opacity-30" />
          <div className="absolute bottom-4 right-4 w-3 h-3 bg-[#3e2723] rounded-full opacity-30" />

          <div className="flex justify-between items-center border-b-2 border-[#d7ccc8] pb-4 mb-8">
            <h2 className="font-black uppercase tracking-widest text-[#5d4037]">
              {filteredScrolls.length} Matching Scrolls Found
            </h2>
            <div className="flex gap-4 text-[10px] font-black uppercase opacity-60">
              <span>Sorted by: Relevance</span>
            </div>
          </div>

          {filteredScrolls.length > 0 ? (
            <div className="grid grid-cols-1 gap-4">
              {filteredScrolls.map((scroll) => (
                <div 
                  key={scroll.id}
                  className="group flex flex-col md:flex-row md:items-center justify-between p-6 bg-[#efebe9]/50 border-l-4 border-[#8d6e63] hover:border-[#b8860b] hover:bg-white transition-all cursor-pointer shadow-sm hover:shadow-md"
                >
                  <div className="space-y-1">
                    <div className="flex items-center gap-3">
                      <Scroll size={18} className="text-[#8d6e63]" />
                      <h3 className="text-xl font-black text-[#3e2723] group-hover:text-[#b8860b] transition-colors uppercase leading-none">
                        {scroll.title}
                      </h3>
                    </div>
                    <div className="flex gap-6 text-xs font-bold text-[#8d6e63] uppercase tracking-wide ml-7">
                      <span className="flex items-center gap-1"><MapPin size={12} /> {scroll.location}</span>
                      <span className="flex items-center gap-1"><Shield size={12} /> {scroll.type}</span>
                    </div>
                  </div>

                  <div className="mt-4 md:mt-0 flex items-center gap-6">
                    <div className="text-right">
                      <p className="text-[10px] uppercase opacity-50 font-black">Reward</p>
                      <p className="font-black text-[#5d4037] flex items-center justify-end gap-1">
                        <Coins size={14} className="text-[#b8860b]" /> {scroll.reward}
                      </p>
                    </div>
                    <div className={`px-3 py-1 text-[10px] font-black rounded text-white uppercase
                      ${scroll.difficulty === 'Hard' ? 'bg-[#8b0000]' : 
                        scroll.difficulty === 'Medium' ? 'bg-[#5d4037]' : 'bg-[#2e4d2e]'}`}>
                      {scroll.difficulty}
                    </div>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="py-20 text-center space-y-4">
              <AlertTriangle size={48} className="mx-auto text-[#8d6e63] opacity-50" />
              <p className="text-2xl font-black text-[#8d6e63] uppercase italic">No scrolls match your inquiry...</p>
              <button 
                onClick={() => setSearchTerm("")}
                className="text-sm font-bold text-[#3e2723] underline decoration-wavy"
              >
                Clear all filters
              </button>
            </div>
          )}
        </main>

        <footer className="text-center">
          <p className="text-[10px] uppercase font-bold text-[#d7ccc8] tracking-[0.4em] opacity-40">
            Official Guild Archive Management System • Year 1272
          </p>
        </footer>
      </div>

      <style dangerouslySetInnerHTML={{ __html: `
        body {
          background-image: url('https://images.alphacoders.com/110/1105802.jpg');
          background-size: cover;
          background-attachment: fixed;
          background-repeat: no-repeat;
          background-position: center;
        }
        input::placeholder {
          font-style: italic;
          opacity: 0.3;
        }
      `}} />
    </div>
  );
};

export default ScrollSearch;
